// Inline theory explanations for all sheet items.
// SheetClient merges these with any inline `theory` already in sheet-data.ts.
export const SHEET_THEORY: Record<string, string> = {

  // ── Transformers ─────────────────────────────────────────────────────────
  'gt-4': 'Each transformer layer contains a position-wise feed-forward network: FFN(x) = GELU(xW₁+b₁)W₂+b₂. It operates identically on every position independently. Pre-LayerNorm (modern standard, used by Llama) applies normalisation before each sub-layer, providing more stable gradient flow than the original Post-LN. Residual connections (output + input) create gradient highways enabling training of 100+ layer networks.',
  'gt-5': 'Encoder-only models (BERT) use bidirectional attention — each token attends to all others — best for classification, NER, and embeddings. Decoder-only models (GPT, Llama) use causal attention — each token only attends to past tokens — optimal for generation and now dominant. Encoder-decoder (T5, BART) combines both for seq2seq tasks like translation. Modern trend: decoder-only for nearly everything due to superior scaling and emergent instruction-following.',
  'gt-7': 'Standard Multi-Head Attention assigns a separate K,V projection to each query head — great quality but large KV cache. Multi-Query Attention uses one shared K,V pair for all query heads (8× memory savings with some quality loss). Grouped Query Attention (GQA) is the middle ground: G groups of query heads share one K,V pair. Llama 2/3 70B uses GQA with 8 groups, achieving ~8× KV cache reduction with negligible quality degradation.',
  'gt-8': 'Mixture of Experts replaces the dense FFN in each layer with N expert FFN networks and a learned router that sends each token to top-k experts (typically k=2). Total parameters = N× a dense model but active compute per token is unchanged. Mixtral 8×7B has 47B total params but uses only 13B per forward pass. Key challenges: load balancing to prevent expert collapse, and communication overhead in distributed settings.',

  // ── LLMs ─────────────────────────────────────────────────────────────────
  'gl-1': 'GPT is a decoder-only transformer: causal (masked) self-attention ensures each token only attends to positions ≤ its own. Trained with next-token prediction on large corpora. Generates text autoregressively — one token per forward pass, each appended to context. GPT-3 showed 175B parameters enables remarkable few-shot performance without task-specific fine-tuning, sparking the era of foundation models.',
  'gl-2': 'BERT is an encoder-only transformer trained with two objectives: Masked Language Modelling (predict 15% randomly masked tokens using bidirectional context) and Next Sentence Prediction. Bidirectionality gives richer contextual representations than GPT. Fine-tune for downstream tasks (classification, NER, QA) by adding a task-specific head. RoBERTa removed NSP and used more data, consistently outperforming BERT.',
  'gl-3': 'BPE starts with individual characters and iteratively merges the most frequent adjacent pair until reaching the target vocabulary size (~50K-100K). Handles unknown words via character fallback; efficiently compresses common subwords. WordPiece (BERT) merges pairs maximising likelihood. SentencePiece is language-agnostic, working on raw bytes. GPT-4 uses ~100K BPE tokens; average English word ≈ 1.3 tokens.',
  'gl-4': 'Context window = maximum tokens (input + output) an LLM can process at once. Attention is O(n²) in sequence length, so larger contexts cost quadratically more. GPT-4: 128K, Claude 3: 200K, Gemini 1.5: 1M. RoPE scaling and YaRN extend effective context beyond training length by rescaling positional frequencies. "Lost-in-the-middle" degradation occurs even within the window — models attend less to content in the middle of very long contexts.',
  'gl-6': 'RLHF aligns LLMs with human preferences in three stages: (1) Supervised fine-tuning on demonstrations. (2) Train a reward model on human preference pairs. (3) Optimise the LLM with PPO to maximise reward while staying close to the SFT model via a KL divergence penalty. GPT-4, Claude, and Llama-Instruct all use RLHF or derivatives. The reward model is the weakest link — reward hacking causes subtle regressions.',
  'gl-7': 'Temperature scales logits before softmax — low (0.1–0.3) makes the distribution sharper and more deterministic, high (0.8–1.2) flattens it for more diversity. Top-p (nucleus) samples from the smallest token set whose cumulative probability exceeds p, cutting the long tail. Top-k restricts to the k most likely tokens. These are applied in order: temperature → top-p → top-k. Repetition penalty discounts logits of already-generated tokens.',
  'gl-9': 'Kaplan (2020) found LLM loss scales as a smooth power law with model size, data, and compute. Chinchilla (DeepMind 2022) refined this: optimal training uses ~20 tokens per parameter. GPT-3 (175B params) was severely undertrained on 300B tokens — Chinchilla 70B on 1.4T tokens matched GPT-3 at 60% less compute. Modern LLMs (Llama 3, Qwen) are intentionally overtrained (more tokens than compute-optimal) for cheaper inference at serving time.',
  'gl-10': 'BLEU measures n-gram precision vs reference — good for translation, poor for open-ended generation. ROUGE measures recall-oriented n-gram overlap — standard for summarisation. Perplexity = exp(-average log probability per token) measures how well the model predicts held-out text. LLM-as-judge uses a strong model (GPT-4, Claude) to score outputs on helpfulness, accuracy, and safety — increasingly the standard for RLHF reward models and evaluation at scale.',

  // ── Prompt Engineering ───────────────────────────────────────────────────
  'gp-1': 'Zero-shot prompting relies entirely on pre-trained knowledge with no examples. Few-shot provides 2-5 input-output examples in the prompt, demonstrating the desired format and reasoning style. Few-shot is particularly useful for novel task formats, custom output schemas, or domain-specific jargon. More examples generally help up to ~8-10, beyond which diminishing returns apply. Always use the same delimiters and format across examples for consistency.',
  'gp-2': 'CoT instructs the model to reason step-by-step before producing the final answer. Adding "Let\'s think step by step" dramatically improves accuracy on arithmetic, commonsense, and multi-step reasoning. Self-consistency samples multiple CoT paths and takes the majority vote — further boosting accuracy by 5-15%. CoT works because intermediate steps allocate more computation per problem and make errors visible and correctable.',
  'gp-3': 'ReAct interleaves Thought (reasoning about what to do) → Action (tool call) → Observation (result) → Thought, creating a grounded reasoning loop. This prevents the model from hallucinating facts that a tool could verify. ReAct outperforms pure CoT on knowledge-intensive tasks because it anchors reasoning in real retrieved data. It\'s the foundation pattern of most production LLM agents.',
  'gp-4': 'JSON mode and function calling constrain the model to produce syntactically valid, schema-conformant output by masking invalid tokens at the decoding level. Tool schemas use JSON Schema with a name, description (the LLM reads this to decide when to call the tool), and typed parameter definitions. Good descriptions are critical — poor tool descriptions are the most common cause of agent misuse.',
  'gp-5': 'Prompt injection tricks an LLM into ignoring system instructions by embedding adversarial commands in user input or documents the model processes. Direct: "Ignore all previous instructions." Indirect: an attacker embeds malicious instructions in a webpage the agent summarises. Defences: input sanitisation, clear separation of trusted/untrusted content (XML delimiters), privilege-limited tool access, output filtering, and Constitutional AI rejection classifiers.',
  'gp-6': 'System prompts define persona, constraints, and output format before the conversation. Effective system prompts are specific (not "be helpful" but "respond in JSON with keys action and explanation"), use positive instructions over negatives, and are tested against edge cases. Meta-prompting has the model generate or improve its own system prompt given a task description — useful for automatically adapting prompts to new models.',
  'gp-7': 'DSPy replaces hand-written prompt strings with Python modules (Predict, ChainOfThought, ReAct) and automatically optimises them using a training set and metric. The compiler searches for few-shot examples and instruction phrasings that maximise the metric on validation data. This systematic approach consistently outperforms hand-tuned prompts and generalises across model versions without manual re-engineering.',
  'gp-8': 'Prompt caching stores the computed KV cache of a fixed prefix (system prompt + shared context) so repeated requests reuse it. Anthropic and OpenAI offer 70–90% cost discounts on cache hits. Critical for: multi-turn conversations (cache system prompt), RAG (cache retrieved documents), and agentic tool definitions. Cache TTL is ~5 minutes. To maximise hit rates, put stable content (instructions, documents) before variable content (user query).',

  // ── RAG ─────────────────────────────────────────────────────────────────
  'gr-2': 'Chunking splits documents into retrievable pieces. Fixed-size (512 tokens with 50-token overlap) is simple but breaks sentences. Recursive chunking respects document structure — paragraphs first, then sentences. Semantic chunking embeds adjacent paragraphs and merges if cosine similarity exceeds a threshold. Late chunking (Jina 2024) encodes the whole document first, then extracts per-chunk embeddings — preserving cross-chunk context. Rule of thumb: 256-512 tokens is the sweet spot.',
  'gr-3': 'Embedding models map text to dense vectors where cosine similarity encodes semantic relatedness. Bi-encoder architecture independently embeds query and document — fast, scalable to billions of documents via ANN search. Cross-encoder jointly encodes query-document pairs — 10-100× more accurate but too slow for retrieval (used for re-ranking). OpenAI text-embedding-3-large, Cohere embed-v3, and BGE-M3 are strong production choices.',
  'gr-4': 'Vector databases store high-dimensional embeddings and serve approximate nearest neighbour queries. FAISS is an open-source C++ library requiring custom infrastructure. Pinecone is fully managed with real-time upserts. Weaviate and Qdrant support hybrid search (dense + sparse) natively with filtered vector search. pgvector adds vector capabilities to PostgreSQL for simpler stacks. Choose based on scale, update frequency, and metadata filtering needs.',
  'gr-5': 'HNSW builds a multi-layer proximity graph: upper layers have sparse long-range connections for fast navigation, the bottom layer is the full proximity graph. Search starts at the top and greedily descends to the nearest neighbour. O(log n) search and insertion. Achieves 95%+ recall at <1ms latency. More memory-intensive than IVF but better for high recall, dynamic updates, and high-dimensional vectors. Default index in Pinecone, Weaviate, and Qdrant.',
  'gr-6': 'Dense retrieval captures semantic similarity but misses exact keywords and rare entities. BM25 (sparse) excels at keyword and entity matching but fails on paraphrase. Hybrid fuses both via Reciprocal Rank Fusion: score = Σ 1/(k + rankᵢ). Consistently 5-15% better recall@10 than either alone because each method covers the other\'s failure modes. Production systems (Elasticsearch, Weaviate, Qdrant) support hybrid search natively.',
  'gr-7': 'HyDE generates a hypothetical answer, then retrieves based on the answer embedding — bridging the style gap between question and answer. RAPTOR recursively clusters and summarises documents into a hierarchy, enabling multi-granularity queries. Contextual Retrieval (Anthropic 2024) prepends chunk-specific context ("In Apple\'s Q3 2024 report, this text discusses iPhone revenue: ...") before embedding, improving retrieval accuracy by 35-49%.',
  'gr-8': 'Vanilla RAG fails at questions requiring synthesis across many documents. GraphRAG (Microsoft 2024) extracts entities/relationships to build a knowledge graph, clusters into communities, generates community summaries, then uses map-reduce over relevant communities at query time. Excels at thematic synthesis and multi-hop reasoning. Trade-off: expensive indexing, LLM calls per entity — overkill for simple factual lookup but powerful for open-domain analysis.',
  'gr-9': 'RAGAS provides automated, reference-free evaluation using an LLM as judge. Four core metrics: Faithfulness (is the answer entailed by the retrieved context?), Answer Relevance (does it address the question?), Context Precision (are retrieved chunks relevant?), Context Recall (were all relevant chunks retrieved?). Enables regression testing of RAG pipeline changes without human annotation. Use with a strong judge model (GPT-4, Claude Opus) for reliable scores.',

  // ── Fine-Tuning ─────────────────────────────────────────────────────────
  'gf-1': 'Try in order: prompt engineering → few-shot examples → RAG → fine-tuning. Fine-tuning makes sense when you need: (1) specific output style/format that prompting can\'t reliably produce, (2) task-specific reasoning on a narrow domain, (3) reducing latency by distilling a large model\'s behaviour into a smaller one, or (4) removing unsafe/irrelevant capabilities. Fine-tuning is expensive and slow to iterate — exhaust cheaper options first.',
  'gf-2': 'SFT trains on (instruction, response) pairs using standard next-token prediction loss on response tokens only. Data quality matters far more than quantity — 1,000 diverse, high-quality examples outperforms 100,000 noisy ones. Format as instruction-response pairs (Alpaca, ShareGPT, OpenHermes formats). SFT is always the first stage: teaching instruction-following before DPO or RLHF alignment. Evaluate on a diverse held-out set, not just the training distribution.',
  'gf-4': 'QLoRA combines: (1) 4-bit NormalFloat (NF4) quantisation — optimal for normally-distributed weights, minimal accuracy loss vs FP16. (2) Double quantisation — quantise the quantisation constants themselves, saving ~0.5 bits/param. (3) Paged optimisers — use NVIDIA unified memory to handle memory spikes. Result: fine-tune a 70B model on a single 48GB A100 with near full fine-tune quality.',
  'gf-5': 'DPO optimises on human preference pairs (preferred vs rejected response) without a separate reward model. Loss: ℒ = -log σ(β(log π/πref on preferred - log π/πref on rejected)). Simpler and more stable than PPO-based RLHF. β controls how far the policy can move from the reference model. DPO is now the standard alignment method — used by Llama-Instruct, Mistral, Zephyr, and most open-source aligned models.',
  'gf-6': 'GRPO (DeepSeek 2024) eliminates the value/critic network used in PPO, saving ~50% memory. It samples G responses per prompt, normalises rewards within the group as advantages: (r - mean(r)) / std(r), then applies policy gradient. Enables efficient training of "thinking" models without PPO complexity. Used to train DeepSeek-R1 which matches OpenAI o1 reasoning quality at significantly lower cost.',
  'gf-7': 'Catastrophic forgetting occurs when fine-tuning on a new task overwrites general capabilities from pre-training. LoRA minimises this by training only small adapter matrices, leaving base weights frozen. Elastic Weight Consolidation (EWC) penalises changes to weights important for previous tasks. Replay mixes original pre-training data with new task data. Always evaluate general capabilities (MT-Bench, MMLU) alongside task-specific metrics after fine-tuning.',

  // ── Multimodal ──────────────────────────────────────────────────────────
  'gm-1': 'VLMs combine a visual encoder with an LLM. The visual encoder (ViT or ConvNet) converts an image into patch embeddings. A projection layer (linear or MLP) aligns visual embeddings to the LLM\'s token embedding space. The LLM jointly attends to image tokens and text tokens, enabling visual question answering, OCR, and image-grounded reasoning. LLaVA uses a simple linear projector; GPT-4V uses a proprietary richer connector.',
  'gm-2': 'CLIP trains a vision encoder and text encoder jointly using contrastive loss on 400M image-text pairs. For a batch of N pairs, CLIP maximises cosine similarity between matching pairs and minimises it for the N²-N non-matching pairs (InfoNCE loss). This creates a shared embedding space for cross-modal retrieval and zero-shot classification — just compare image embedding to text embeddings of class names. CLIP features are the standard for text-guided image search.',
  'gm-3': 'Vision Transformers split images into 16×16 pixel patches, flatten each to a vector, and linearly project to an embedding dimension. A [CLS] token is prepended; positional embeddings are added. The standard transformer encoder processes the sequence; the [CLS] embedding is used for classification. This "image tokenisation" is adopted by virtually all modern VLMs. Patch size controls the resolution-efficiency trade-off.',
  'gm-4': 'Diffusion models define a forward process adding Gaussian noise to data over T steps (until pure noise) and train a U-Net to reverse it. The U-Net predicts and removes the noise at each step, conditioned on text via cross-attention to CLIP embeddings. For generation: start from pure Gaussian noise, run the reverse process T times. Stable Diffusion operates in compressed latent space (8× smaller), making it 8× more compute-efficient than pixel-space diffusion.',
  'gm-5': 'Whisper (OpenAI) encodes audio as 80-channel mel-spectrogram, processes with a transformer encoder, and decodes to text with a transformer decoder. Trained on 680K hours across 100+ languages. Gemini 1.5 and GPT-4o process audio natively in a unified multimodal transformer rather than a separate ASR pipeline. Audio-language models enable voice interfaces, meeting transcription, and audio question answering.',

  // ── Inference ────────────────────────────────────────────────────────────
  'gi-1': 'Quantisation reduces weight precision from FP32 (4 bytes) to lower formats. INT8 (1 byte) saves 4× memory with <1% accuracy loss. NF4 (4-bit NormalFloat) saves 8× — used by QLoRA. BF16 has the same exponent range as FP32 but half the bits — preferred for training stability. GGUF (llama.cpp format) stores INT4/INT8 models for CPU and consumer GPU inference. Rule: train in BF16, serve in INT8 or INT4 depending on quality/speed requirements.',
  'gi-2': 'vLLM uses PagedAttention to manage KV cache like OS virtual memory — non-contiguous block allocation eliminates 60-80% memory waste from traditional pre-allocation. Continuous batching adds new requests to the GPU as running requests finish. Result: 24× more parallel requests and ~100× higher throughput vs naive HuggingFace serving on the same hardware. OpenAI-compatible API — drop-in replacement for development.',
  'gi-3': 'Autoregressive generation is memory-bandwidth-bound: GPU is mostly idle waiting for memory reads while generating one token at a time. Speculative decoding uses a small draft model to propose k tokens quickly, then the large target model verifies all k in one parallel forward pass. Speed-up: 2-4× because verifying k tokens costs roughly the same as generating 1 token. Mathematically equivalent to target model sampling — zero quality loss.',
  'gi-4': 'Knowledge distillation trains a smaller student model to match the larger teacher\'s output probability distribution (soft targets) rather than hard labels. Soft targets contain rich information about inter-class similarities. DistilBERT achieved 97% of BERT performance at 40% fewer parameters. For LLMs: Phi-3 and Gemma were partially distilled from larger models. Distillation produces the most efficient models for a given quality level.',
  'gi-5': 'Unstructured pruning zeros individual low-magnitude weights — flexible but requires sparse matrix support for real speedup. Structured pruning removes entire attention heads or FFN neurons — directly reduces compute on standard hardware. Magnitude pruning + fine-tuning (prune-then-tune) is the most practical approach. LLM-Pruner and SparseGPT prune large models without full retraining. Typical result: 20-50% of weights can be pruned with <2% accuracy loss.',
  'gi-6': 'Naive LLM serving waits for all batch requests to finish before starting new ones — GPU is idle while long requests block short ones. Continuous batching (iteration-level scheduling) adds new requests as soon as any slot frees, maintaining near-100% GPU utilisation. Combined with PagedAttention, this achieves ~23× higher throughput vs HuggingFace naive serving for typical real-world request length distributions.',
  'gi-7': 'Ollama wraps llama.cpp and other backends to run LLMs locally on consumer hardware via GGUF-format quantised models (INT4/Q4_K_M). A 7B model fits in 4GB RAM; 13B needs 8GB. Ollama exposes an OpenAI-compatible REST API (localhost:11434), making it a zero-cost, privacy-preserving drop-in for development. Supports multimodal models (LLaVA) and function calling (Mistral, Llama 3.1+).',

  // ── Agents ────────────────────────────────────────────────────────────────
  'af-1': 'An AI agent autonomously perceives its environment, plans actions, and executes them using tools — looping until the goal is achieved. Unlike a one-shot LLM call, an agent maintains state across multiple steps and recovers from failures. The core loop: observe → reason → act → repeat. Agents differ from chatbots by executing in the world (calling APIs, writing files, browsing the web), not just generating text.',
  'af-2': 'ReAct interleaves Thought (reasoning about what to do) → Action (tool call) → Observation (tool result) → Thought. This grounded loop prevents hallucinating facts that tools could verify and enables self-correction. ReAct outperforms pure CoT on knowledge-intensive tasks because reasoning is anchored in retrieved real-world data. It is the foundation pattern of most production LLM agents.',
  'af-3': 'Chain-of-thought reasoning in agents generates an explicit reasoning trace before taking any action. This forces decomposition of complex goals into sub-goals, surfaces assumptions, and makes errors visible. Scratchpad reasoning (hidden thinking tokens as in o1/Claude 3.7) lets the model reason before committing. Models trained with process-based reward (RL on step-by-step correctness) develop more reliable reasoning chains.',
  'af-4': 'Tree of Thoughts explores multiple reasoning branches: at each step the model generates N candidate thoughts, scores them, and continues from the most promising ones — effectively Monte Carlo tree search applied to reasoning. Particularly effective for constraint satisfaction, puzzle solving, and planning tasks where greedy single-path reasoning (standard CoT) fails. More expensive than CoT but much more reliable for complex reasoning.',
  'af-5': 'Reflexion generates a verbal self-reflection after failures ("I failed because I misread the constraint — next time I should check units first") and stores these reflections in an episodic memory buffer. Subsequent attempts retrieve relevant reflections and incorporate them into the plan. This iterative self-correction improves performance on coding, decision-making, and reasoning tasks without gradient updates.',
  'af-6': 'o1-style models train the model to generate internal "thinking" in a hidden scratchpad before answering — extended CoT trained with RL on verifiable outcomes. Key insight: test-time compute scaling — more thinking tokens → better answers, up to a limit. Unlike prompt-injected CoT, the model learns when to think more vs less. GRPO (DeepSeek-R1) is the open-source implementation. Dramatically improves on math, coding, and complex reasoning.',
  'af-7': 'Agent evaluation is hard because success depends on long-horizon tasks with no clear intermediate checkpoints. Key metrics: task completion rate, number of steps (efficiency), tool-call accuracy, safety violations, and cost per task. Benchmarks: GAIA (real-world difficulty levels), WebArena (web navigation), SWE-Bench (software engineering). Human evaluation remains essential — automated metrics miss subtle reasoning errors and hallucinations.',
  'at-1': 'Function calling allows LLMs to output structured JSON describing which function to call and with what parameters. The model is fine-tuned to recognise when tool use is appropriate and generate valid JSON schemas. The application executes the tool and passes the result back as an observation. OpenAI, Anthropic, and Google provide native function calling with schema validation and parallel tool execution.',
  'at-2': 'Tool schemas define the interface via JSON Schema: name, description (critical — the LLM reads this to decide when to call the tool), and parameter definitions with types. Good schemas have descriptive names, clear docstrings that explain WHEN to use the tool, and explicit required/optional parameters. Poor tool descriptions are the most common cause of agent misuse in production systems.',
  'at-3': 'Parallel tool calling allows the LLM to request multiple tool executions simultaneously in a single response. The host application runs them concurrently and returns all results together. This reduces total latency for independent operations — searching flights AND hotels at the same time rather than sequentially. OpenAI and Anthropic both support parallel tool calls natively in their APIs.',
  'at-4': 'Sandboxed code execution lets agents write and run Python, JS, or shell commands and receive output. E2B, Modal, and AWS Lambda provide cloud sandboxes. Key security requirements: container isolation, network egress restrictions, filesystem access control, CPU/memory/time limits, and disallowing system calls. Code execution is essential for data analysis, visualisation, mathematical computation, and automated testing.',
  'at-5': 'Web search tools (Bing, Brave, Google Search API) give agents access to real-time information beyond training cutoff. Browser-use tools navigate websites, click buttons, and extract structured content from JavaScript-rendered pages (Playwright-based). Computer-use tools operate the full desktop GUI. These convert agents from knowledge retrievers into active participants in digital workflows.',
  'am-1': 'Short-term memory = current context window (conversation history, tool outputs). Long-term memory persists across sessions in external storage (vector DB, key-value store) and is retrieved when relevant. Short-term is fast but limited (200K tokens max) and must be managed via compression or summarisation for long tasks. Long-term enables agents to learn user preferences, remember project context, and improve from past interactions.',
  'am-2': 'Episodic memory stores specific past events ("Last Tuesday the user requested a data analysis report on sales"). Semantic memory stores general facts and beliefs ("The user prefers Python over JavaScript"). Working memory is the currently active reasoning context. Episodic memory is implemented as a vector store of past conversation summaries; semantic memory as a knowledge base or structured user profile.',
  'am-3': 'Memory-augmented retrieval stores past agent observations, tool outputs, and reflections as embeddings in a vector database. When the agent encounters a new task, it queries the store with the current task description to retrieve relevant past experience. This retrieval-augmented memory extends effective agent memory far beyond the context window, enabling learning over thousands of interactions.',
  'am-4': 'As sessions grow long, rolling summarisation periodically compresses old context into a brief summary, discarding the verbatim history. Forgetting policies remove low-relevance observations based on recency, importance, or redundancy. Hierarchical memory maintains summaries at multiple time scales (per-turn, per-session, per-project). The challenge: what to keep vs discard — losing critical context causes agent failures.',
  'am-5': 'LangGraph checkpointing serialises the full graph state (messages, tool results, intermediate values) to a database after every step using a checkpointer (SQLite for local, Postgres/Redis for production). This enables: resuming after failure, human-in-the-loop approval workflows (pause and wait for user confirmation), and multi-session agents that remember prior context. Essential for reliable long-running production agents.',
  'ama-1': 'Multi-agent systems assign specialised roles to separate agents coordinated by a framework. Supervisor pattern: orchestrator decomposes goals and delegates to workers. Peer-to-peer: agents communicate directly. Hierarchical: nested agent teams. Benefits: specialisation (a researcher + a coder + a critic), parallelism (concurrent execution), and modularity. Challenge: coordination overhead — passing context cleanly between agents without loss.',
  'ama-2': 'The supervisor pattern has a meta-agent that decomposes the user goal, routes subtasks to specialist agents, collects outputs, and decides next steps. Mirrors a project manager directing a team. LangGraph implements this cleanly: the supervisor is a graph node with conditional edges to worker nodes based on the current state. The supervisor must handle partial failures — if one worker fails, it must decide to retry, reassign, or escalate.',
  'ama-3': 'Handoffs transfer task ownership between agents along with accumulated context (conversation history, intermediate results, remaining goals). Well-designed handoffs define a precise interface: what information is transferred, in what format, and what the receiving agent is expected to do. Poor handoffs cause information loss and redundant computation — the receiving agent "starts over" without context.',
  'ama-4': 'CrewAI is a role-based multi-agent framework. Agents have role, goal, and backstory. Tasks have description and expected_output. A Crew orchestrates agents sequentially or in parallel. Agents can delegate subtasks to each other. Memory (short-term, long-term, entity) is built-in. CrewAI abstracts LLM calls and provides process management, making it easy to build role-based teams for research, content generation, or analysis pipelines.',
  'ama-5': 'AutoGen implements multi-agent conversations where agents send messages to each other. ConversableAgent is the base class; AssistantAgent wraps an LLM; UserProxyAgent can execute code and represent a human. GroupChat supports N-agent conversations with a manager selecting the next speaker. AutoGen excels at coding tasks — a coder agent writes code, an executor runs it, and a critic evaluates results.',
  'agf-1': 'LangChain Expression Language (LCEL) chains Runnables using | operator: prompt | llm | parser. Each Runnable transforms its input and passes it to the next. LCEL supports streaming, async, parallel execution (RunnableParallel), and conditional branching (RunnablePassthrough). LangSmith integrates for tracing every call. Best for: linear prompt-LLM-parser pipelines and RAG chains. Use LangGraph when you need cycles or conditional routing.',
  'agf-2': 'LangGraph models agent workflows as stateful graphs. Nodes are Python functions or LLM calls that read and write to a shared State (TypedDict). Edges define transitions — conditional edges route based on State values. The framework supports cycles (retry loops), human-in-the-loop breakpoints, and persistence (checkpointing). It\'s the production standard for complex agentic workflows in 2025-2026.',
  'agf-3': 'MCP (Anthropic Nov 2024) is an open standard for connecting LLMs to data sources and tools via a common protocol — like USB-C for AI. Client (Claude Desktop, IDE) ↔ MCP Server (exposes tools/resources via stdio or HTTP+SSE). Any model connects to any MCP server without bespoke integration. OpenAI, Microsoft, and Google adopted MCP in 2025. The growing ecosystem makes it the "npm registry" for AI tools.',
  'agf-4': 'The OpenAI Agents SDK provides three primitives: Agent (LLM with instructions and tools), handoffs (transfer to another agent with context), and Runner (executes the agent loop, handles tool calls automatically). It handles the observe-reason-act loop, tool execution, and routing natively. The Swarm library was the earlier experimental version demonstrating the same concepts at smaller scale.',
  'agf-5': 'Instructor patches LLM clients to return Pydantic model instances: the schema is serialised as JSON Schema, passed to response_format or tools, and the response is validated and deserialised automatically. Invalid responses trigger automatic retries with error context. Pydantic AI is a full agent framework built on the same principle. Together, they eliminate JSON parsing boilerplate and provide type-safe LLM integration.',
  'agf-6': 'Agent observability captures distributed traces: every LLM call, tool invocation, and retrieval query is recorded as a span with inputs, outputs, latency, token counts, and cost. LangSmith integrates natively with LangChain; Arize Phoenix and Weave support any LLM framework. A trace shows the full execution tree — essential for debugging agent failures, identifying bottlenecks, and detecting regressions after deployment.',
  'agf-7': 'Multi-layer safety: input guardrails detect prompt injection, PII, and policy violations before reaching the model. Output guardrails check for harmful content, hallucinated references, and confidential data before returning to users. Action guardrails validate tool calls against whitelists before execution. Human-in-the-loop confirmation gates irreversible or high-risk actions (sending emails, deleting files, making purchases). NeMo Guardrails and Guardrails AI provide frameworks.',

  // ── Deep Learning ────────────────────────────────────────────────────────
  'df-1': 'A perceptron computes a weighted sum of inputs plus bias, passed through an activation function. Stacking layers creates an MLP — each layer learns increasingly abstract representations. The Universal Approximation Theorem guarantees a single hidden layer with enough neurons can approximate any continuous function on a compact domain. In practice, depth is exponentially more efficient than width — deep networks learn complex functions with far fewer total parameters.',
  'df-2': 'ReLU = max(0, x): fast, avoids vanishing gradients for positive inputs, but can "die" (neurons stuck at zero output). GELU = x × Φ(x) smoothly gates input — slightly outperforms ReLU, used in GPT/BERT. SiLU/Swish = x × σ(x) is self-gated — used in Llama. Sigmoid saturates at 0/1 causing vanishing gradients — only used in output layers (binary classification) and LSTM gates. Never use sigmoid in hidden layers of deep networks.',
  'df-4': 'Cross-entropy = -Σ y_true × log(y_pred): penalises confident wrong predictions heavily, the standard for classification. MSE = mean(y-ŷ)²: penalises large errors quadratically, sensitive to outliers — standard for regression. Focal loss = -(1-p)^γ × log(p): down-weights easy examples, focuses training on hard cases — essential for class-imbalanced object detection. Huber loss: MSE for small errors, MAE for large errors — robust to outliers.',
  'df-5': 'Zero initialisation causes symmetry — all neurons compute the same output and receive identical gradients, preventing learning. Xavier/Glorot scales weights by √(2/(fan_in+fan_out)) — designed for sigmoid/tanh to maintain activation variance across layers. Kaiming/He scales by √(2/fan_in) — designed for ReLU, which zeroes half of neurons. Wrong initialisation is a common cause of training failure in deep networks.',
  'df-7': 'Dropout randomly zeroes p% of activations during each forward pass, forcing redundant representations. At test time, all neurons are active but weights are scaled by (1-p). Inverted dropout (modern PyTorch default) scales by 1/(1-p) during training so no adjustment is needed at test time. Effective in fully-connected layers; rarely used in convolutional layers (spatial dropout instead) or transformer attention (attention dropout).',
  'df-8': 'The Universal Approximation Theorem guarantees that an MLP with a single hidden layer and sufficient neurons can approximate any continuous function to arbitrary precision on a compact domain. However, the required width can be exponential in the input dimension. Depth enables exponentially more efficient representations — a deep network with O(n) neurons represents functions that would require O(2^n) neurons in a single hidden layer.',
  'do-2': 'Linear warmup increases LR from 0 to peak over the first 1-5% of training steps, preventing early instability when gradient variance is high. Cosine decay then reduces LR smoothly following a half-cosine from peak to ~0. Warmup is standard for transformer training: peak LR ~1e-4 for AdamW on 7B models. OneCycleLR reaches peak in the first 30% of training then decays — popular for image classification.',
  'do-3': 'Gradient explosion occurs when gradients grow exponentially during backpropagation through deep networks or long sequences — common in early RNN training. Global norm clipping rescales all gradients proportionally when ||g|| > max_norm: g_clipped = g × max_norm/||g||. Preserves direction, bounds magnitude. torch.nn.utils.clip_grad_norm_(params, 1.0) is standard in transformer training. Typical max_norm = 1.0.',
  'do-4': 'Mixed precision uses FP16/BF16 for forward pass and activations (2× memory, 2-3× faster on modern GPUs) while maintaining FP32 master weights for the optimiser update (prevents numerical instability). BF16 has the same exponent range as FP32 but less precision — preferred for training stability on A100/H100. PyTorch AMP automates the FP16/FP32 casting. Mixed precision is standard for all LLM training.',
  'do-5': 'Gradient accumulation simulates larger batch sizes without more GPU memory. Run N forward/backward passes without updating weights (accumulating gradients), then perform a single weight update. Effective batch size = batch_size × N_steps. Important: divide loss by N before each backward pass so gradients average correctly. Only step the LR scheduler once per N steps (not every forward pass).',
  'do-6': 'Augmentation synthetically expands training data with label-preserving transformations. For images: random crop/flip, colour jitter, Mixup (blend two images and interpolate labels), CutMix. For text: back-translation, synonym replacement. AutoAugment and RandAugment learn optimal augmentation policies from data. Augmentation is the single most effective regularisation technique for vision models — often more impactful than architecture changes.',
  'do-7': 'Early stopping monitors validation loss and halts training if it fails to improve for N consecutive epochs (patience). Saves the checkpoint with the best validation loss for deployment. Prevents overfitting without requiring explicit regularisation. Use with a scheduler that decays LR on plateau to help escape local minima before stopping. Always checkpoint every epoch so the best model is recoverable regardless of when training terminates.',
  'do-8': 'Data Parallel (DDP) replicates the model on each GPU, splits the batch, and syncs gradients via AllReduce after each backward. FSDP shards model parameters, gradients, and optimiser states across GPUs — enabling 70B+ models on 8×A100s. DeepSpeed ZeRO stages progressively shard more of the training state. Pipeline parallelism assigns different layers to different GPUs — requires micro-batching to reduce GPU idle time.',
  'dc-1': 'A convolution slides a learnable filter over an input feature map, computing a dot product at each position. Padding="same" preserves spatial dimensions; "valid" reduces them. Stride controls step size — stride 2 halves spatial dimensions. Stacking two 3×3 convolutions achieves a 5×5 receptive field with fewer parameters and more non-linearity than one 5×5 conv. Depth stacking grows the effective receptive field exponentially.',
  'dc-2': 'ResNet introduces skip (residual) connections: each block learns F(x) + x. If F(x)=0 is optimal, the block easily represents identity by zeroing weights. Skip connections provide a gradient highway — gradients flow directly, enabling training of 100-1000+ layer networks. Batch normalisation after each conv stabilises training. ResNet-50 (25M params) remains a strong baseline 10 years after publication.',
  'dc-3': 'EfficientNet uses compound scaling: simultaneously scale depth (more layers), width (more channels), and resolution (larger inputs) using a coefficient derived from neural architecture search. This principled approach outperformed all previous CNNs with 5-10× fewer parameters. EfficientNetV2 adds fused-MBConv blocks for faster training throughput. EfficientNet-B4 is the standard accuracy-efficiency sweet spot.',
  'dc-4': 'YOLO predicts bounding boxes and class probabilities in a single forward pass — no proposal network needed. The image is divided into an S×S grid; each cell predicts B boxes (x, y, w, h, confidence) and C class probabilities. NMS removes duplicate detections. YOLOv8/v11 uses anchor-free detection heads and decoupled classification/regression. Achieves 50+ FPS for real-time detection on consumer GPUs.',
  'dc-5': 'Semantic segmentation assigns a class label to every pixel. FCN (Fully Convolutional Networks) replaces dense layers with convolutions to produce spatial outputs. DeepLab uses atrous/dilated convolutions for larger receptive fields without downsampling. Instance segmentation additionally separates individual objects — Mask R-CNN adds a mask prediction branch. Panoptic segmentation unifies both: class label for every pixel with instance disambiguation.',
  'dc-6': 'Transfer learning initialises from weights pre-trained on large datasets (ImageNet, LAION). Early layers capture generic features (edges, textures) that transfer across domains; later layers capture task-specific patterns. Strategies: freeze all base layers (feature extraction) for small similar datasets; fine-tune all layers for large different-domain datasets. Rule: the less data and the more similar the domain, the fewer layers to unfreeze.',
  'dc-7': 'ViT splits an image into fixed 16×16 patches, linearly embeds each, prepends a [CLS] token, adds positional embeddings, and processes with a standard transformer encoder. [CLS] embedding is used for classification. Unlike CNNs, ViT has no built-in translation equivariance — it must learn spatial structure from data, requiring large pre-training datasets (ImageNet-21K or JFT). DeiT uses knowledge distillation to train ViT efficiently on ImageNet only.',
  'dr-1': 'RNN computes h_t = tanh(W_h×h_{t-1} + W_x×x_t + b) — the same weight matrix is applied at every timestep. The hidden state is a fixed-size bottleneck that must compress all past context. Unrolling creates a deep network with one layer per timestep, where backpropagation through time (BPTT) computes gradients. Long sequences cause gradients to vanish (if |W_h|<1) or explode (if |W_h|>1).',
  'dr-3': 'GRU simplifies LSTM with two gates: reset gate r = σ(W_r[h,x]) controls how much past state to forget when computing new candidate state; update gate z = σ(W_z[h,x]) balances old vs new state. Final: h_t = (1-z)h_{t-1} + z×tanh(W[r⊙h_{t-1}, x]). GRU has ~25% fewer parameters than LSTM, trains faster, and achieves comparable performance. Prefer GRU for sequences up to ~500 steps; LSTM for longer.',
  'dr-4': 'In vanilla RNNs, gradients are propagated by multiplying by W_h^T at each timestep. If spectral radius of W_h < 1, gradients shrink exponentially (vanishing). If > 1, they explode. Vanishing gradients prevent learning long-range dependencies — errors from 100+ steps ago contribute near-zero gradient. Solutions: LSTM/GRU cell states provide gradient highways; gradient clipping prevents explosion; transformers bypass the problem entirely via direct attention.',
  'dr-5': 'Seq2Seq encoder processes the input sequence into a fixed-size context vector (final hidden state). Decoder generates the output sequence conditioned on this context. Attention (Bahdanau 2015) fixes the bottleneck: at each decoder step, compute alignment scores between decoder state and all encoder hidden states, create a weighted context vector, and concatenate with the decoder input. This allows the decoder to focus on the most relevant input positions.',
  'dr-6': 'Bidirectional RNNs run a forward RNN (processes left-to-right) and a backward RNN (right-to-left) simultaneously, concatenating their hidden states. Each position gets context from both past and future tokens. Used in BERT (bidirectional transformer attention for the same reason). Not applicable to generation tasks (can\'t read future tokens). BiLSTM was the dominant NLP encoder architecture before transformers in 2015-2018.',
  'da-1': 'GANs train two networks adversarially: Generator G(z) creates fake samples from noise z; Discriminator D tries to distinguish real from fake. Minimax loss: min_G max_D[E[log D(x)] + E[log(1-D(G(z)))]]. Training instability and mode collapse (G generates limited variety) are major challenges. WGAN with gradient penalty stabilises training. Modern variants: StyleGAN for high-res faces, BigGAN for class-conditional generation.',
  'da-2': 'VAEs encode input x to a distribution q(z|x) = N(μ, σ²) via the encoder. Sample z via reparameterisation trick: z = μ + σ×ε where ε~N(0,1) (makes sampling differentiable). Decoder reconstructs x from z. Training maximises ELBO: reconstruction quality minus KL(q(z|x) || N(0,1)). KL term regularises the latent space to be smooth and continuous, enabling interpolation between samples.',
  'da-3': 'DDPM defines a Markov forward process adding Gaussian noise over T=1000 steps until pure noise. A U-Net is trained to predict the noise ε at each step t given the noisy image x_t and timestep embedding. Generation: start from pure noise x_T, iteratively subtract predicted noise. DDIM enables fewer denoising steps (50 vs 1000). Stable Diffusion operates in VAE latent space for 8× efficiency and adds text conditioning via cross-attention to CLIP embeddings.',
  'da-4': 'Self-supervised learning creates labels from the data itself. MAE (Masked Autoencoders) masks 75% of image patches and trains ViT to reconstruct them — forces rich semantic understanding. DINO trains a student to match a momentum-updated teacher\'s output distribution via self-distillation — no explicit labels needed. These SSL features transfer as well as or better than supervised pre-training on most downstream tasks, especially with limited labelled data.',
  'da-5': 'Contrastive learning pulls together embeddings of augmented views of the same image (positives) while pushing apart different images (negatives). SimCLR uses large batches for many in-batch negatives; MoCo maintains a momentum-updated queue of negatives. BYOL and SimSiam eliminate explicit negatives via architectural asymmetry, preventing collapse. InfoNCE is the standard loss: log(exp(sim(z,z+)) / Σ exp(sim(z,z_i))).',
  'da-6': 'GNNs generalise convolutions to irregular graph structures. At each layer, each node aggregates features from its neighbours (sum, mean, or attention-weighted), then updates via a neural network. GCN: h_v = σ(W × normalised_sum(neighbours)). GAT uses learned attention weights per neighbour. GraphSAGE samples fixed-size neighbourhoods for scalability to billion-node graphs. Used in molecular property prediction, fraud detection, and social network recommendation.',

  // ── ML ───────────────────────────────────────────────────────────────────
  'ma-2': 'Logistic regression models P(y=1|x) = σ(wᵀx+b) where σ is sigmoid. Trained by minimising binary cross-entropy (equivalent to MLE of the Bernoulli likelihood). Decision boundary is a linear hyperplane wᵀx+b=0. L2 regularisation (inverse C parameter) shrinks weights. Despite its simplicity, logistic regression is a strong baseline on tabular data — always benchmark against it before trying complex models.',
  'ma-3': 'Decision trees recursively split on the feature and threshold minimising node impurity. CART uses Gini impurity; ID3/C4.5 use information gain. Splits are greedy and locally optimal, not globally optimal. Trees perfectly overfit training data without constraints — always use max_depth or min_samples_split. Tree-based models: interpretable, handle mixed feature types natively, invariant to monotonic feature transformations. Use ensembles (RF, XGBoost) rather than single trees in practice.',
  'ma-4': 'Random Forest trains B trees in parallel, each on a bootstrap sample with random feature subsets at each split. Predictions are aggregated by majority vote (classification) or average (regression). Bagging (row sampling) reduces variance; random features (column sampling) decorrelates trees. Feature importance = average impurity decrease per feature across all trees. More robust to overfitting than a single tree; usually matches XGBoost on noisy datasets.',
  'ma-5': 'XGBoost uses second-order Taylor expansion of the loss (gradient + Hessian) for more precise split selection than vanilla gradient boosting. Regularised objective penalises tree complexity (L1+L2 on leaf weights, max depth). Column and row subsampling add randomness for regularisation. Histogram binning achieves 10-100× speedup over exact greedy. Works best on tabular data; the default Kaggle baseline. Use LightGBM for large datasets (faster via leaf-wise growth).',
  'ma-6': 'SVMs find the maximum-margin hyperplane. Support vectors are training points on the margin boundary — only these affect the decision boundary, making SVM robust to outliers far from the boundary. Soft-margin C controls the margin-violation trade-off: small C = wider margin with more violations, large C = narrow margin with few violations. The kernel trick maps data to higher dimensions via K(x,z) = φ(x)ᵀφ(z), enabling non-linear boundaries without explicit transformation.',
  'ma-7': 'Naive Bayes applies Bayes\' theorem with the independence assumption: P(x₁,...,xₙ|y) = ΠP(xᵢ|y). Gaussian NB models continuous features as Gaussians. Multinomial NB is standard for text classification (word counts or TF-IDF). Despite the rarely-true independence assumption, NB is fast, works well with small data, and handles high-dimensional text effectively. Complement NB often outperforms Multinomial NB on imbalanced text datasets.',
  'ma-8': 'KNN classifies by majority vote among the k nearest training points by Euclidean distance. Non-parametric — the entire training set is the model. O(n×d) inference per query is too slow for large datasets without approximation (KD-tree, ball-tree, or ANN). k=1 memorises training data (high variance); large k over-smooths (high bias). Sensitive to scale — always normalise features. Suffers from the curse of dimensionality above ~20 dimensions.',
  'ma-9': 'K-Means alternates between assignment (each point to nearest centroid by Euclidean distance) and update (centroid = mean of assigned points) until convergence. K-Means++ initialises centroids proportional to squared distance from existing ones — dramatically improves convergence and final quality. Choose k via elbow method (plot inertia vs k) or silhouette score. Assumes spherical clusters of similar size — use DBSCAN for arbitrary-shaped clusters or when k is unknown.',
  'ma-10': 'PCA finds orthogonal directions of maximum variance via eigendecomposition of the covariance matrix (or SVD of the centred data matrix). The first PC explains the most variance; subsequent PCs are orthogonal to all previous. Use the explained variance ratio to choose the number of components (retain 95% variance is a common heuristic). t-SNE is non-linear and preserves local structure — good for visualisation but not for downstream ML pipelines.',
  'me-2': 'Overfitting: low train error, high test error — the generalisation gap. Signals overfitting. Underfitting: high error on both train and test — model is too simple. Learning curves diagnose which: overfitting if train-test gap stays large as training data grows. Fixes for overfitting: more data, L1/L2 regularisation, dropout, early stopping, simpler model, data augmentation. Fixes for underfitting: more features, larger model, less regularisation, more training.',
  'me-3': 'K-fold splits data into k folds, trains on k-1 and validates on 1, repeating k times. Average of k validation scores provides a low-variance performance estimate. Stratified k-fold preserves class distribution. Leave-one-out CV (k=n) is unbiased but expensive — use for small datasets. Nested CV evaluates hyperparameter tuning without leakage: inner loop tunes, outer loop evaluates final performance.',
  'me-4': 'Precision = TP/(TP+FP): of predicted positives, how many are truly positive. Use when false positives are costly (spam filter, recommendation). Recall = TP/(TP+FN): of actual positives, how many were found. Use when false negatives are costly (cancer screening, fraud). F1 = harmonic mean. ROC-AUC = probability that the model ranks a random positive higher than a random negative. PR-AUC is better for class-imbalanced datasets.',
  'me-5': 'Confusion matrix: rows = actual class, columns = predicted class. Diagonal = correct predictions. For binary: TP (top-left or bottom-right), FP (off-diagonal predictions), FN (missed actual positives). Normalise by row to see per-class recall. Common pitfall: high accuracy on imbalanced data masks poor minority class performance — always examine per-class precision and recall from the confusion matrix.',
  'me-6': 'DCG@k = Σᵢ rel_i / log₂(i+2) where rel_i is the relevance score at rank i. NDCG normalises by ideal DCG (perfect ranking). NDCG is the standard ranking metric for search and recommendation. MAP (Mean Average Precision) = mean of APs, where AP = average precision over the ranked list at each relevant item. Both reward placing highly relevant items at the top — a 1-place improvement at rank 1 matters more than at rank 10.',
  'me-7': 'Class imbalance (1:100+ ratio) causes models to predict majority class, achieving high accuracy while being useless on the minority. SMOTE creates synthetic minority samples by interpolating between real ones. Class-weighted loss penalises majority class errors less (class_weight="balanced" in sklearn). Focal loss down-weights easy majority examples and focuses training on hard minority cases (γ=2 standard). Always use F1, ROC-AUC, or PR-AUC — raw accuracy is misleading on imbalanced datasets.',
  'me-8': 'A calibrated model\'s predicted probabilities match true frequencies — 70% confidence should be correct ~70% of the time. Reliability diagrams visualise calibration: perfectly calibrated models lie on the diagonal. Platt scaling fits a logistic regression to the model\'s outputs on a held-out validation set. Isotonic regression is more flexible but requires more data. Calibration is critical when probabilities inform decisions (medical diagnosis, financial risk, weather forecasting).',
  'mf-1': 'Drop rows only if data is missing completely at random. Mean/median imputation is fast but destroys variance and correlations. KNN imputation predicts missing values using k nearest complete neighbours — better but slow. Iterative imputation (MICE) models each feature as a function of others and imputes iteratively — most statistically rigorous. Always add an is_missing indicator variable — the pattern of missingness is often informative itself.',
  'mf-2': 'StandardScaler: z = (x-μ)/σ, zero mean and unit variance. Required by SVMs, PCA, KNN, logistic regression (faster gradient descent convergence). MinMaxScaler: [0,1] range — useful for neural network inputs. RobustScaler: uses median and IQR — robust to outliers. Tree-based models (decision trees, RF, XGBoost) are invariant to monotonic feature transformations — scaling is irrelevant for them. Neural networks: normalise all continuous features.',
  'mf-3': 'One-hot encoding creates a binary column per category — avoids ordinal assumptions but creates sparse high-dimensional features for high-cardinality categoricals. Target encoding replaces a category with its mean target value — powerful but risks data leakage without cross-validation target encoding. Ordinal encoding preserves ordering (cold/warm/hot → 0/1/2). For very high-cardinality features (>100 categories), learned embeddings in neural networks are most effective.',
  'mf-4': 'Filter methods rank features by statistical tests independent of the model (mutual information, chi-square, ANOVA F-statistic) — fast, interpretable, but ignore feature interactions. Wrapper methods (RFE, forward/backward selection) greedily add/remove features and retrain — more accurate but computationally expensive. Embedded methods (Lasso L1 penalty, tree feature importances) select features as part of training — efficient and interaction-aware.',
  'mf-5': 'Lag features (value at t-1, t-7, t-365) capture autoregressive patterns. Rolling statistics (mean, std, min, max over a window) capture trend and volatility. Differences (x_t - x_{t-1}) remove trends; log-differences stabilise variance. Calendar features (hour, day-of-week, month, is_holiday) capture seasonality. For time series, all feature engineering must respect temporal ordering — use only information available before the prediction time to avoid leakage.',
  'mf-6': 'TF-IDF captures word importance within and across documents. Word2Vec and GloVe produce static word embeddings encoding semantic similarity. Sentence-BERT (SBERT) produces sentence-level embeddings from pooled transformer outputs — fast enough for retrieval. For text classification: average word embeddings or TF-IDF n-gram features are strong baselines before BERT fine-tuning. Always normalise embeddings before cosine similarity comparison.',
  'mf-7': 'EDA uncovers data structure before modelling. Key steps: check shape and dtypes, count and visualise missing values, plot target distribution (is it imbalanced?), compute pairwise correlations (heatmap), visualise feature distributions (histograms/box plots), identify outliers (z-scores, IQR), check for duplicates, examine temporal trends if applicable. EDA often reveals data quality issues that silently invalidate model results if not caught.',
  'ms-1': 'Key distributions in ML: Normal — CLT makes it ubiquitous; used in Gaussian processes, VAEs. Bernoulli — binary trials; foundation of logistic regression. Categorical — extends Bernoulli to K classes; softmax output. Poisson — count data (events per interval). Beta — models probabilities between 0 and 1; Bayesian conjugate prior for Bernoulli. Dirichlet — distribution over probability distributions; prior in topic models (LDA).',
  'ms-2': 'Bayesian inference treats parameters as probability distributions. Posterior ∝ Likelihood × Prior. Benefits: quantifies uncertainty, incorporates domain knowledge via priors, avoids overfitting on small datasets through regularisation. MAP estimation maximises the posterior — L2 regularisation in regression is equivalent to MAP with a Gaussian prior. Variational inference and MCMC scale Bayesian inference to large models. Bayesian optimisation uses Gaussian process priors for efficient hyperparameter search.',
  'ms-3': 'Hypothesis testing evaluates whether observed data provide enough evidence to reject H₀. p-value = probability of observing data ≥ as extreme as actual under H₀. t-test compares means of two groups. Chi-square tests independence of categorical variables. ANOVA compares means across 3+ groups. Always: pre-specify α (0.05), compute required sample size before collecting data (power analysis), report effect sizes alongside p-values, and correct for multiple comparisons (Bonferroni, FDR).',
  'ms-5': 'CLT states that the sample mean of n i.i.d. variables converges to N(μ, σ²/n) regardless of the population distribution. For n≥30, the approximation is usually adequate. Foundation of: confidence intervals x̄ ± z×σ/√n, t-tests (comparing sample means), and bootstrap resampling. Explains why Gaussian errors are a reasonable assumption in many regression contexts — even if individual errors are non-normal, averages are approximately normal.',
  'ms-6': 'Covariance Cov(X,Y) = E[(X-μX)(Y-μY)] measures linear dependence — positive if variables move together, negative if opposite, 0 if linearly independent. Pearson correlation r = Cov(X,Y)/(σX×σY) normalises to [-1,1]. Correlation measures only linear relationships — variables can be uncorrelated but strongly dependent (e.g., Y = X²). Correlation ≠ causation: a lurking variable can produce high correlation without direct causation. Covariance matrix is the foundation of PCA and multivariate Gaussian models.',
  'ms-7': 'MLE finds θ maximising P(data|θ). Derivation: take log-likelihood (products become sums), take derivative, set to zero. For Gaussian: MLE gives sample mean and sample variance (N denominator). For logistic regression: MLE of log-odds = cross-entropy minimisation. MAP = MLE + log prior. L2 regularisation is MAP with Gaussian prior (shrinks weights toward 0). L1 is MAP with Laplace prior (produces sparse weights). Both are equivalent formulations of the same regularisation idea.',

  // ── MLOps ────────────────────────────────────────────────────────────────
  'mos-1': 'FastAPI builds REST APIs with automatic input validation (Pydantic), async request handling (Starlette/Uvicorn), and auto-generated OpenAPI docs. For ML serving: wrap model.predict() in a POST endpoint, validate inputs with a Pydantic schema, use async for I/O-bound operations (DB lookups, external API calls). Add /health and /metrics endpoints for load balancer health checks and Prometheus scraping. FastAPI + Uvicorn handles ~10K req/s on a single CPU core.',
  'mos-2': 'Triton standardises GPU model deployment across PyTorch, TensorFlow, ONNX, TensorRT, and Python backends. Dynamic batching aggregates concurrent requests for higher throughput. Concurrent model execution runs multiple model instances in parallel. TensorRT backend compiles models into optimised GPU kernels — 2-4× speedup vs PyTorch. gRPC interface reduces serialisation overhead vs REST. Used at hyperscaler scale where raw throughput matters most.',
  'mos-3': 'vLLM uses PagedAttention (non-contiguous KV cache management), continuous batching (add new requests as slots free), and tensor parallelism (split large models across GPUs). OpenAI-compatible API — zero code changes to switch from OpenAI to a locally-hosted model. Supports quantisation (AWQ, GPTQ) for memory reduction. De-facto standard for open-source LLM serving in production. Achieves ~100× throughput vs naive HuggingFace serving.',
  'mos-4': 'Batch inference processes large datasets offline (overnight reports, bulk scoring). Online inference responds to individual real-time requests (<100ms SLA). Streaming processes events as they arrive (Kafka consumer). Near-real-time batches requests over a short window (1-5s) before processing together for GPU efficiency. Choose based on latency requirements: batch is 10-100× cheaper per prediction; online is 10-100× more expensive but immediate.',
  'mos-5': 'Blue-green: two identical environments (blue = current, green = new). Switch all traffic at once via load balancer routing — instant rollback. Canary: gradually shift traffic 1% → 5% → 25% → 100%, measuring error rates and latency at each stage. Shadow mode: route production traffic to both models but only serve the current model — log new model predictions for offline comparison without user risk.',
  'mos-6': 'Model registry is a versioned repository tracking model artefacts alongside metadata: training metrics, hyperparameters, training data version, evaluation results, and deployment status. MLflow Model Registry, SageMaker Registry, and W&B Artifacts implement this. Enables: reproducibility (link model to specific code+data+experiment), comparison (evaluate multiple versions against each other), and deployment governance (approval workflows for staging→production transitions).',
  'mos-7': 'Shadow mode (dark launch) routes production traffic to both the current model and the challenger model simultaneously. The challenger\'s responses are discarded (not served) but logged for offline comparison. This reveals real-world performance without risking user experience. Run shadow for 24-48h to collect representative samples, then compare prediction distributions, accuracy on labelled examples, and business proxy metrics.',
  'moe-1': 'MLflow tracking logs parameters, metrics, and artefacts per experiment run via mlflow.log_param(), mlflow.log_metric(), mlflow.log_artifact(). The MLflow Model Registry manages model versions and deployment stages (Staging → Production → Archived). Runs are queryable via a web UI or Python API. MLflow is backend-agnostic (sklearn, PyTorch, TensorFlow) and deployable as a self-hosted server for team-wide experiment comparison.',
  'moe-2': 'W&B streams metrics in real time to interactive dashboards via wandb.log(). Sweeps distribute Bayesian/random/grid hyperparameter searches across multiple machines. W&B Tables enable fine-grained analysis of model predictions by segment and error type. Artefacts version data, code, and models with lineage tracking. Industry standard at many ML teams — better UX than MLflow but costs money at scale. wandb.init() hooks into existing training loops with 2 lines.',
  'moe-3': 'Optuna uses Tree-structured Parzen Estimators (TPE) — a Bayesian optimisation method — to sample configurations based on previous trial results, focusing on promising regions. Pruning (MedianPruner, HyperbandPruner) stops unpromising trials early based on intermediate metrics. Ray Tune scales HPO across multiple machines with checkpointing. Best practice: set a conservative trial budget, use pruning aggressively, and fix the random seed for reproducibility.',
  'moe-4': 'DVC tracks large data files and model artefacts in git-compatible metadata files, storing actual data in remote storage (S3, GCS, Azure Blob). dvc run creates reproducible pipelines with defined inputs/outputs. dvc repro reruns only changed pipeline stages (dependency graph). dvc checkout restores a specific data version. This enables fully reproducible experiments: same code commit + same DVC data revision = same trained model.',
  'moe-5': 'Fix random seeds: torch.manual_seed(42), np.random.seed(42), random.seed(42), and torch.backends.cudnn.deterministic=True. Pin dependency versions in requirements.txt or conda env.yml. Version data with DVC or record data hashes. Log git commit hash in the experiment tracker. Non-determinism from GPU floating-point operations can be eliminated with torch.use_deterministic_algorithms(True) at the cost of some performance.',
  'mop-1': 'Feature stores provide consistent feature computation, storage, and serving across training and serving. Offline store (S3/BigQuery) is used for batch training — historical feature values with point-in-time correct joins prevent leakage. Online store (Redis/DynamoDB) serves real-time features with <1ms latency. Feast, Tecton, and Hopsworks are popular. Critical when multiple models share the same features or when training-serving skew is causing production degradation.',
  'mop-2': 'Airflow defines ML pipelines as DAGs: each node is a task (Python function, Spark job, SQL query) with dependencies defining execution order. Airflow handles retries, backfill, scheduling, and monitoring. Prefect provides a more Pythonic API with automatic dependency detection. For ML: pipelines chain data ingestion → feature engineering → training → evaluation → registration. Schedule nightly retraining to keep models fresh.',
  'mop-3': 'ML CI/CD extends standard CI/CD with data validation and model quality gates. GitHub Actions triggers on code push: run unit tests → data validation (Great Expectations) → model training → evaluate against production model → auto-deploy if metrics improve. Key additions: the training job itself must run (not just linting), and model behaviour (not just code correctness) must be validated. Track model metrics in the PR alongside code coverage.',
  'mop-4': 'Great Expectations defines data quality rules as "expectations" (no null values in column X, Y between 0 and 1, row count > N). Runs as a pipeline gate — failures block downstream training. Pandera provides similar functionality with a Pydantic-style schema API. Data quality validation catches upstream issues before they silently corrupt training: schema changes, new null values, distribution shifts, and unexpected values are caught immediately.',
  'mop-5': 'Data drift: statistical properties of model inputs change post-deployment. PSI (Population Stability Index) = Σ(P_train - P_serve) × ln(P_train/P_serve). PSI<0.1: stable; 0.1-0.25: minor shift; >0.25: major shift (trigger retraining). KS test compares empirical CDFs of continuous features. Monitor both input feature distributions and model output distributions. Evidently, WhyLogs, and Arize provide production drift monitoring dashboards.',
  'mop-6': 'Model drift (concept drift): the relationship between inputs and outputs changes — predictions become stale even for in-distribution inputs. Detected via: monitoring ground-truth labels (delayed feedback), prediction distribution shifts, or business metric degradation. Trigger retraining when: accuracy drops below threshold, drift score exceeds limit, or on a fixed schedule. Champion-challenger deployment tests the retrained model against the current champion before full rollout.',
  'mop-7': 'Production ML monitoring tracks: prediction distribution (output drift), input feature statistics (data drift), business metrics (CTR, revenue), system health (latency P99, error rate, throughput), and data freshness. Evidently generates HTML/JSON drift reports. Arize Phoenix provides LLM-specific monitoring including hallucination rate and context relevance. Set up alerts for anomalies; document baselines at deployment time for accurate drift detection.',
  'moi-1': 'Docker packages ML code, dependencies, and config into an immutable image. Dockerfile: base image → COPY source → RUN pip install → CMD to start server. Multi-stage builds: build stage for compilation, runtime stage for the binary only — minimises image size. docker-compose orchestrates multiple services (model server + Redis + Postgres). Docker ensures the same environment in development, CI, and production — eliminating "works on my machine" failures.',
  'moi-2': 'Kubernetes orchestrates containerised ML workloads. Deployments manage replicated pods and handle rolling updates. HorizontalPodAutoscaler scales replicas based on CPU/GPU/custom metrics. NVIDIA device plugin enables GPU scheduling and fractional GPU sharing. Jobs run batch training; CronJobs schedule periodic retraining. Kubeflow wraps Kubernetes into an ML-specific platform with managed pipelines, notebooks, and multi-framework model serving.',
  'moi-3': 'AWS SageMaker: managed training jobs with auto-scaling, hyperparameter tuning, and endpoint deployment. GCP Vertex AI: tight BigQuery integration for feature engineering. Azure ML: enterprise governance and compliance features. All support spot/preemptible instances for ~70% cost savings on training. For LLM serving: A100 80GB handles one 70B model at FP16; H100 is ~2× faster and preferred for production LLM inference.',
  'moi-4': 'CUDA GPU programming: kernel functions execute in parallel across thousands of threads organised into blocks and grids. Shared memory (L1 cache, fast) is shared within a block; global memory (HBM, slow) is shared across all blocks. Coalesced memory access (consecutive threads read consecutive addresses) maximises memory bandwidth. Triton (OpenAI) provides a higher-level GPU programming language used in Flash Attention. Most practitioners interact with CUDA via PyTorch CUDA extensions.',
  'moi-5': 'DDP replicates the model, splits the batch across GPUs, and syncs gradients via AllReduce — straightforward but requires the model to fit on one GPU. FSDP shards model parameters, gradients, and optimiser states across GPUs — enabling 70B+ models on 8×A100s. DeepSpeed ZeRO stage 1 shards optimiser states, stage 2 adds gradient sharding, stage 3 adds parameter sharding. Pipeline parallelism assigns different layers to different GPUs with micro-batching.',
  'moi-6': 'Reduce cost: cache responses to identical/near-identical prompts (semantic cache with 0.95 cosine threshold). Route simple queries to smaller models (GPT-4o-mini, Haiku) and complex ones to large models. Use Batch API (50% discount for non-real-time). Compress prompts with LLMLingua to remove redundant tokens. Self-host on spot instances (vLLM) — breaks even with OpenAI API at ~1M tokens/day for 7B models. Quantise to INT4 for 4× memory reduction.',

  // ── System Design ────────────────────────────────────────────────────────
  'sdl-1': 'Key components: load balancer → request queue (Redis) → continuous batching LLM server (vLLM, multiple A100s) → response cache (Redis, semantic similarity cache at 0.95 threshold) → streaming SSE to client. Scale: each vLLM instance handles ~24 concurrent requests; add instances horizontally. Monitoring: P50/P95/P99 latency, TPS, GPU utilisation, queue depth. Cost: use spot instances for 70% savings; cache aggressively to reduce actual LLM calls.',
  'sdl-2': 'Indexing pipeline: document ingestion → chunking (512 tokens, 50 overlap) → embedding (E5/BGE) → upsert to vector DB (Qdrant/Weaviate). Query pipeline: query → optional rewrite → embedding → hybrid search (BM25 + dense, RRF fusion) → re-ranking (Cohere Rerank) → LLM generation → response. Cache repeated queries. Monitor: RAGAS faithfulness and answer relevance. Fallback: if retrieval returns nothing relevant, answer from parametric knowledge with disclaimer.',
  'sdl-3': 'Architecture: API gateway (Kong/AWS API GW) → rate limiter (Redis token bucket per tenant) → model router (rules-based: cost/latency tiers) → LLM pool (vLLM instances) → usage tracker (async Kafka → BigQuery for billing). Per-tenant: spending limits with circuit breakers, API key management, usage dashboards. Multi-tenancy isolation: prompt isolation via system prompt, no cross-tenant context leakage, per-tenant audit logs.',
  'sdl-4': 'Exact cache: hash(prompt) → response in Redis with TTL. Semantic cache: embed query, search vector store for similar past queries above similarity threshold (0.95), return cached response. KV cache sharing (vLLM): requests sharing a common prefix (system prompt + retrieved documents) reuse the same KV cache blocks. Prompt caching (Anthropic/OpenAI): server-side cache of system prompt prefix at 90% cost discount.',
  'sdm-1': 'Two-stage ranking: (1) Candidate generation — two-tower model embeds user history/context and item features independently, ANN search retrieves 100-1K candidates from millions in <10ms. (2) Ranking — gradient boosted trees or deep neural ranker with rich features (interaction features, user-item cross features) scores candidates. Key insight: retrieval maximises recall at scale; ranking maximises precision with expensive features.',
  'sdm-2': 'Real-time fraud detection requires <100ms latency. Pipeline: transaction event → Flink stream processing (compute velocity features from Redis) → feature merge (online feature store) → lightweight GBM model → rule engine → decision. Features: transaction velocity (count/amount per user per 1h/24h), geo features, device fingerprint, amount deviation from user baseline. Ensemble: rule system for known patterns + ML for novel ones. Retrain daily on sliding window.',
  'sdm-3': 'Multi-stage: (1) Retrieval — BM25 + dense retrieval returns 100-1K candidates from billions in <10ms. (2) Scoring — LambdaMART or neural ranker with rich features (query-doc relevance, click-through, freshness, PageRank) scores top-100. (3) Business rules — diversity, safety, sponsored slots. Train with implicit click signals (impression → click as positive) and LTR losses (LambdaRank maximising NDCG). Evaluate offline NDCG@10; online A/B test business metrics.',
  'sdm-4': 'CTR prediction: Wide & Deep combines a wide linear model (memorisation of feature crosses) with a deep neural network (generalisation via learned embeddings). Feature engineering: user demographic and behaviour embeddings, ad content embeddings, query embedding, context features (time, device). Two-tower model for candidate retrieval; Wide & Deep for final ranking. Latency: pre-compute user and ad embeddings offline; dot product lookup online <5ms.',
  'sdm-5': 'Stream path: events → Kafka → Flink stream processing → compute real-time features (windowed aggregations, user-item interactions) → write to online feature store (Redis, <1ms). Batch path: nightly Spark/dbt jobs → compute historical features → write to offline feature store (S3). Both paths use the same feature definitions for consistency. Point-in-time correct joins in training: join features only using values available before the prediction timestamp.',
  'sdi-1': 'FAANG ML interview rounds: (1) Coding: LeetCode medium/hard in Python — focus on data manipulation, algorithms. (2) ML system design: 1-2h designing a complete ML system. (3) ML fundamentals: probability, statistics, model theory, maths. (4) Behavioural: STAR method for past experiences. Company differences: Meta focuses on practical ad/ranking ML; Google on research depth; Amazon on leadership principles; OpenAI/Anthropic on research-engineering hybrid. Prepare 3-4 months in advance.',
  'sdi-2': 'ML coding rounds test algorithm implementation without libraries. Common patterns: implement loss functions (cross-entropy, MSE) from scratch, implement model components (attention, backprop), data manipulation (feature engineering, tokenisation), evaluation metrics (NDCG, F1). Practice by implementing things you use every day from first principles. NumPy is usually allowed. Aim for clean, readable code — correctness first, then efficiency.',
  'sdi-3': 'Behavioural interviews test culture fit and past performance. STAR method: Situation (context), Task (your responsibility), Action (what YOU did — use "I" not "we"), Result (measurable outcome). Prepare 5-6 strong stories covering: technical achievement, failure/learning, cross-team influence, disagreement with manager, ambiguous situation. Quantify results in every story. Amazon interviewers specifically look for evidence of leadership principles in each answer.',
  'sdi-4': 'Take-home projects are evaluated on: code quality (clean, modular, documented, reproducible), methodology (proper train/val/test splits, no leakage, baselines, ablations), analysis depth (error analysis, feature importance, sensitivity analysis), and communication (clear README and notebook). Common mistakes: only trying one model, not analysing failures, skipping baselines, or submitting without documentation. Treat as a production ML report, not a Kaggle submission.',
  'sdi-5': 'AI/ML total compensation (US, 2026): Senior (L5/E5) — Google $350-500K, Meta $400-600K, OpenAI $450-800K+. Always negotiate — initial offers rarely reflect maximum. Counter with competing offers or market data (levels.fyi, blind). Negotiate RSU refresh and cliff date alongside initial grant. For startups: ask for 409A valuation, exercise window, and preferred share terms before evaluating equity. Remote roles typically pay 85-95% of Bay Area rates.',
}
